mapper.select:
select * from(
select @RN:=@RN+1 AS rnum, a.*
from(
select * from post
where post_status = 0
and category_idx=#{category_idx}
order by post_idx desc
) a, (select @RN:=0)b
) c inner join member m on c.member_idx=m.member_idx
where c.rnum Between #{begin} and #{end}

SELECT  * FROM post p inner join file f
WHERE p.post_idx = #{post_idx}
group by p.post_idx

mapper.update:
UPDATE post
SET post_status = 1
WHERE post_idx = #{post_idx}

UPDATE post
SET post_views = post_views + 1
WHERE post_idx = #{post_idx}

UPDATE post p
INNER JOIN file f ON p.post_idx = f.post_idx

    p.post_title = #{post_title},
    p.post_content = #{post_content}

WHERE p.post_idx = #{post_idx}

mapper.select:
SELECT a.* FROM ( SELECT ROW_NUMBER() OVER(ORDER BY post_idx DESC) AS rnum, p.*, m.member_nickname FROM post p LEFT JOIN member m ON p.member_idx = m.member_idx
p.post_title LIKE CONCAT ('%', #{searchValue}, '%')
p.post_content LIKE CONCAT('%', #{searchValue}, '%')
m.member_nickname LIKE CONCAT('%', #{searchValue}, '%')
)a where a.rnum BETWEEN #{begin} AND #{end};
